class Solution(object):
    def winningPlayerCount(self, n, pick):
        from collections import defaultdict
        cnt = defaultdict(lambda: defaultdict(int))
        for player, color in pick:
            cnt[player][color] += 1
        winners = 0
        for i in range(n):
            if any(c > i for c in cnt[i].values()):
                winners += 1
        return winners
